import sys

def solve():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))

    max_xor = 1 << 9  # Since a_i <= 500, max possible XOR is 512-1
    dp = [-1] * max_xor
    dp[0] = 0  # empty subsequence

    for num in a:
        for x in range(max_xor):
            if dp[x] < num:
                new_x = x ^ num
                if dp[new_x] < num:
                    dp[new_x] = num

    res = []
    for x in range(max_xor):
        if dp[x] != -1:
            res.append(x)
    res.sort()
    print(len(res))
    print(' '.join(map(str, res)))

